THOUGHT: I have successfully generated both JaCoCo and Clover reports. Now, I need to create a file that identifies lines covered by JaCoCo but not Clover, and vice versa.

To achieve this, I will perform the following steps:
1.  **Extract JaCoCo covered lines:** I will parse the `target/site/jacoco/jacoco.xml` report. For each class, I will extract its package name and source filename. Then, for each line within that class, if the `ci` (covered instructions) attribute is greater than 0, I will record the full path (package/filename) and line number.
2.  **Extract Clover covered lines:** I will parse the `target/site/clover/clover.xml` report. Similar to JaCoCo, I will extract the package name (converting dots to slashes for consistency) and source filename. For each line, if `ci` is greater than 0, I will record the full path and line number.
3.  **Compare and generate output:** I will use the `comm` command to compare the sorted lists of covered lines from JaCoCo and Clover.
    *   `comm -23` will show lines unique to JaCoCo (covered by JaCoCo but not Clover).
    *   `comm -13` will show lines unique to Clover (covered by Clover but not JaCoCo).
4.  **Write to file:** The comparison results will be written to `coverage_comparison.txt`.
5.  **Clean up:** Remove temporary files created during the process.

I will create a shell script to encapsulate these steps and execute it.

```bash
cat <<'EOF' > compare_coverage.sh
#!/bin/bash

# Extract JaCoCo covered lines
awk '
/<package name="([^"]*)">/{
    current_package = $0;
    match(current_package, /name="([^"]*)"/, arr);
    package_name = arr[1];
}
/<class .* sourcefilename="([^"]+\.java)">/{
    current_class = $0;
    match(current_class, /sourcefilename="([^"]+\.java)"/, arr);
    filename = arr[1];
}
/<line nr="([0-9]+)" mi="[0-9]+" ci="([0-9]+)"\/>/{
    if (package_name != "" && filename != "") {
        line_nr_tag = $0;
        match(line_nr_tag, /nr="([0-9]+)"/, nr_arr);
        match(line_nr_tag, /ci="([0-9]+)"/, ci_arr);
        if (ci_arr[1] > 0) {
            print package_name "/" filename ":" nr_arr[1]
        }
    }
}' target/site/jacoco/jacoco.xml > jacoco_covered_lines.txt

# Extract Clover covered lines
awk '
/<package name="([^"]*)">/{
    current_package = $0;
    match(current_package, /name="([^"]*)"/, arr);
    package_name = gensub(/\./, "/", "g", arr[1]); # Replace dots with slashes
}
/<sourcefile name="([^"]+\.java)">/{
    current_sourcefile = $0;
    match(current_sourcefile, /name="([^"]+\.java)"/, arr);
    filename = arr[1];
}
/<line nr="([0-9]+)" mi="[0-9]+" ci="([0-9]+)"\/>/{
    if (package_name != "" && filename != "") {
        line_nr_tag = $0;
        match(line_nr_tag, /nr="([0-9]+)"/, nr_arr);
        match(line_nr_tag, /ci="([0-9]+)"/, ci_arr);
        if (ci_arr[1] > 0) {
            print package_name "/" filename ":" nr_arr[1]
        }
    }
}' target/site/clover/clover.xml > clover_covered_lines.txt

# Compare and generate output
echo "Lines covered by JaCoCo but not Clover:" > coverage_comparison.txt
comm -23 <(sort jacoco_covered_lines.txt) <(sort clover_covered_lines.txt) >> coverage_comparison.txt
echo "" >> coverage_comparison.txt
echo "Lines covered by Clover but not JaCoCo:" >> coverage_comparison.txt
comm -13 <(sort jacoco_covered_lines.txt) <(sort clover_covered_lines.txt) >> coverage_comparison.txt

# Clean up temporary files
rm jacoco_covered_lines.txt clover_covered_lines.txt

echo "Coverage comparison report generated in coverage_comparison.txt"
EOF

chmod +x compare_coverage.sh && ./compare_coverage.sh
```

